91	  }
92	  const ids = listTelegramAccountIds(cfg);
93	  const resolved = resolveListedDefaultAccountId({
94	    accountIds: ids,
95	    configuredDefaultAccountId: normalizeOptionalAccountId(cfg.channels?.telegram?.defaultAccount),
96	  });
97	  if (resolved !== ids[0] || ids.includes(DEFAULT_ACCOUNT_ID) || ids.length <= 1) {
98	    return resolved;
