118	export function mergeTelegramAccountConfig(
119	  cfg: OpenClawConfig,
120	  accountId: string,
121	): TelegramAccountConfig {
122	  const {
123	    accounts: _ignored,
124	    defaultAccount: _ignoredDefaultAccount,
125	    groups: channelGroups,
126	    ...base
127	  } = (cfg.channels?.telegram ?? {}) as TelegramAccountConfig & {
128	    accounts?: unknown;
129	    defaultAccount?: unknown;
130	  };
131	  const account = resolveTelegramAccountConfig(cfg, accountId) ?? {};
132	
133	  // In multi-account setups, channel-level `groups` must NOT be inherited by
134	  // accounts that don't have their own `groups` config.  A bot that is not a
135	  // member of a configured group will fail when handling group messages, and
136	  // this failure disrupts message delivery for *all* accounts.
137	  // Single-account setups keep backward compat: channel-level groups still
138	  // applies when the account has no override.
139	  // See: https://github.com/openclaw/openclaw/issues/30673
140	  const configuredAccountIds = Object.keys(cfg.channels?.telegram?.accounts ?? {});
141	  const isMultiAccount = configuredAccountIds.length > 1;
142	  const groups = account.groups ?? (isMultiAccount ? undefined : channelGroups);
143	
144	  return { ...base, ...account, groups };
145	}
