176	export function resolveTelegramAccount(params: {
177	  cfg: OpenClawConfig;
178	  accountId?: string | null;
179	}): ResolvedTelegramAccount {
180	  const baseEnabled = params.cfg.channels?.telegram?.enabled !== false;
181	
182	  const resolve = (accountId: string) => {
183	    const merged = mergeTelegramAccountConfig(params.cfg, accountId);
184	    const accountEnabled = merged.enabled !== false;
185	    const enabled = baseEnabled && accountEnabled;
186	    const tokenResolution = resolveTelegramToken(params.cfg, { accountId });
187	    debugAccounts("resolve", {
188	      accountId,
189	      enabled,
190	      tokenSource: tokenResolution.source,
191	    });
192	    return {
193	      accountId,
194	      enabled,
195	      name: merged.name?.trim() || undefined,
196	      token: tokenResolution.token,
197	      tokenSource: tokenResolution.source,
198	      config: merged,
199	    } satisfies ResolvedTelegramAccount;
200	  };
201	
202	  // If accountId is omitted, prefer a configured account token over failing on
203	  // the implicit "default" account. This keeps env-based setups working while
204	  // making config-only tokens work for things like heartbeats.
205	  return resolveAccountWithDefaultFallback({
206	    accountId: params.accountId,
207	    normalizeAccountId,
208	    resolvePrimary: resolve,
209	    hasCredential: (account) => account.tokenSource !== "none",
210	    resolveDefaultAccountId: () => resolveDefaultTelegramAccountId(params.cfg),
211	  });
212	}
