## Step 7 — `extensions/pulseboard/src/normalize.ts`

Pure functions for PulseBoard target normalization. No SDK imports — only local logic.

```typescript
// PulseBoard target normalization
// Boards: strings starting with "#" (e.g., "#general")
// DMs: alphanumeric usernames (e.g., "alice")

const BOARD_PATTERN = /^#[^\s]+$/u;
const USERNAME_PATTERN = /^[a-z0-9_-]+$/iu;

export function isBoardTarget(raw: string): boolean {
  return raw.trim().startsWith("#");
}

export function looksLikePulseboardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) return false;
  return BOARD_PATTERN.test(trimmed) || USERNAME_PATTERN.test(trimmed);
}

export function normalizePulseboardTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) return undefined;

  // Strip "pulseboard:" prefix if present
  let target = trimmed;
  if (target.toLowerCase().startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("#")) {
      target = `#${target}`;
    }
  }
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }

  if (!target || !looksLikePulseboardTargetId(target)) return undefined;
  return target;
}
```

**Gotchas:**
- The board pattern (`#...`) must not allow spaces in board names. PulseBoard boards are `#word` style.
- The username pattern must be permissive enough to match real usernames but not so permissive it matches URLs or IRC-style `nick!user@host` strings.
- Do not import SDK utilities here; keep this file pure TypeScript with no dependencies.

