Stub probe — PulseBoard has no real API to connect to.

```typescript
import type { CoreConfig, PulseboardProbe } from "./types.js";
import { resolvePulseboardAccount } from "./accounts.js";

function formatError(err: unknown): string {
  if (err instanceof Error) return err.message;
  return typeof err === "string" ? err : JSON.stringify(err);
}

export async function probePulseboard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseboardProbe> {
  const account = resolvePulseboardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseboardProbe = {
    ok: false,
    serverUrl: account.serverUrl,
    username: account.username,
  };

  if (!account.configured) {
    return { ...base, error: "missing apiKey, serverUrl, or username" };
  }

  // Stub: no real PulseBoard API to probe.
  // A real implementation would issue an HTTP health-check against account.serverUrl.
  const started = Date.now();
  try {
    // Simulate a quick connectivity check (stub always succeeds when configured).
    await Promise.resolve();
    return { ...base, ok: true, latencyMs: Date.now() - started };
  } catch (err) {
    return { ...base, error: formatError(err) };
  }
}
```

**Gotchas:**
- `PulseboardProbe` must satisfy `BaseProbeResult` (has `ok: boolean; error?: string`). Make sure the field definitions in `types.ts` do not conflict with what `createComputedAccountStatusAdapter` in `channel.ts` expects from `probe`.
- The probe is called by `createComputedAccountStatusAdapter`'s `probeAccount` callback. Match its signature exactly: `async ({ cfg, account, timeoutMs }) => probePulseboard(cfg as CoreConfig, { accountId: account.accountId, timeoutMs })`.

