## Step 10 — `extensions/pulseboard/src/send.ts`

Stub send function. Relies on `getPulseboardRuntime()` for the runtime handle.

```typescript
import { resolvePulseboardAccount } from "./accounts.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseboardResult = {
  messageId?: string;
};

export async function sendMessagePulseboard(
  to: string,
  text: string,
  opts?: { cfg?: CoreConfig; accountId?: string },
): Promise<SendPulseboardResult> {
  const runtime = getPulseboardRuntime();
  const cfg = (opts?.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseboardAccount({ cfg, accountId: opts?.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiKey, serverUrl, and username in channels.pulseboard).`,
    );
  }

  if (!to.trim()) {
    throw new Error("PulseBoard target must be non-empty");
  }
  if (!text.trim()) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  // Record outbound activity (catches "PulseBoard runtime not initialized" gracefully).
  try {
    runtime.channel.activity.record({
      channel: "pulseboard",
      accountId: account.accountId,
      direction: "outbound",
    });
  } catch (error) {
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }

  // Stub: real implementation would call PulseBoard HTTP API here.
  return { messageId: undefined };
}
```

**Gotchas:**
- The runtime activity recording is wrapped in a try/catch that swallows only the "not initialized" error — exact same pattern as IRC's `recordIrcOutboundActivity`. This allows `send.ts` to be called in tests or CLI contexts without a running gateway.
- The stub returns `{ messageId: undefined }` since no real API call is made. A real implementation would return the server-assigned message ID.

