  { account: ResolvedPulseboardAccount; cfg: CoreConfig }
>(
  // No group-policy warnings for PulseBoard (boards are a simple list, not a policy system).
);

export const pulseboardPlugin: ChannelPlugin<ResolvedPulseboardAccount, PulseboardProbe> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: { ...meta, quickstartAllowFrom: true },
      setup: pulseboardSetupAdapter,
      setupWizard: pulseboardSetupWizard,
      capabilities: {
        chatTypes: ["direct", "group"],
        blockStreaming: true,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: PulseboardChannelConfigSchema,
      config: {
        ...pulseboardConfigAdapter,
        isConfigured: (account) => account.configured,
        describeAccount: (account) =>
          describeAccountSnapshot({
            account,
            configured: account.configured,
            extra: {
              serverUrl: account.serverUrl,
              username: account.username,
              apiKeySource: account.apiKeySource,
            },
          }),
      },
      messaging: {
        normalizeTarget: normalizePulseboardTarget,
        targetResolver: {
          looksLikeId: looksLikePulseboardTargetId,
          hint: "<#board|username>",
        },
      },
      resolver: {
        resolveTargets: async ({ inputs, kind }) => {
          return inputs.map((input) => {
            const normalized = normalizePulseboardTarget(input);
            if (!normalized) {
              return { input, resolved: false, note: "invalid PulseBoard target" };
            }
            if (kind === "group") {
              const groupId = isBoardTarget(normalized) ? normalized : `#${normalized}`;
              return { input, resolved: true, id: groupId, name: groupId };
            }
            if (isBoardTarget(normalized)) {
              return { input, resolved: false, note: "expected user target" };
            }
            return { input, resolved: true, id: normalized, name: normalized };
          });
        },
      },
      directory: createChannelDirectoryAdapter({
        listPeers: async (params) => listPulseboardDirectoryPeersFromConfig(params),
        listGroups: async (params) => {
          const entries = await listPulseboardDirectoryGroupsFromConfig(params);
          return entries.map((entry) => ({ ...entry, name: entry.id }));
        },
      }),
      status: createComputedAccountStatusAdapter<ResolvedPulseboardAccount, PulseboardProbe>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ account, snapshot }) => ({
          ...buildBaseChannelStatusSummary(snapshot),
          serverUrl: account.serverUrl,
          username: account.username,
          probe: snapshot.probe,
          lastProbeAt: snapshot.lastProbeAt ?? null,
        }),
        probeAccount: async ({ cfg, account, timeoutMs }) =>
          probePulseboard(cfg as CoreConfig, { accountId: account.accountId, timeoutMs }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            serverUrl: account.serverUrl,
            username: account.username,
            apiKeySource: account.apiKeySource,
          },
        }),
      }),
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          const statusSink = createAccountStatusSink({
            accountId: ctx.accountId,
            setStatus: ctx.setStatus,
          });
          if (!account.configured) {
            throw new Error(
              `PulseBoard is not configured for account "${account.accountId}" (need apiKey, serverUrl, and username in channels.pulseboard).`,
            );
          }
          ctx.log?.info(
            `[${account.accountId}] starting PulseBoard provider (${account.serverUrl})`,
          );
          await runStoppablePassiveMonitor({
            abortSignal: ctx.abortSignal,
            start: async () =>
              await monitorPulseboardProvider({
                accountId: account.accountId,
                config: ctx.cfg as CoreConfig,
                runtime: ctx.runtime,
                abortSignal: ctx.abortSignal,
                statusSink,
              }),
          });
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseboardUser",
        message: PAIRING_APPROVED_MESSAGE,
        normalizeAllowEntry: (entry) => normalizePulseboardTarget(entry.toLowerCase()) ?? "",
        notify: async ({ id, message }) => {
          const normalized = normalizePulseboardTarget(id);
          if (!normalized || isBoardTarget(normalized)) {
            throw new Error(`invalid PulseBoard pairing id: ${id}`);
          }
          await sendMessagePulseboard(normalized, message);
        },
      },
    },
    security: {
      resolveDmPolicy: resolvePulseboardDmPolicy,
      collectWarnings: collectPulseboardSecurityWarnings,
    },
    outbound: {
      base: {
        deliveryMode: "direct",
        chunker: chunkTextForOutbound,
        chunkerMode: "markdown",
        textChunkLimit: 4000,
      },
      attachedResults: {
        channel: "pulseboard",
        sendText: async ({ cfg, to, text, accountId }) =>
          await sendMessagePulseboard(to, text, {
            cfg: cfg as CoreConfig,
            accountId: accountId ?? undefined,
          }),
        sendMedia: async ({ cfg, to, text, mediaUrl, accountId }) =>
          await sendMessagePulseboard(
            to,
            mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text,
            { cfg: cfg as CoreConfig, accountId: accountId ?? undefined },
          ),
      },
    },
  });
```

**`monitorPulseboardProvider` stub (defined in same file or as a local function):**
```typescript
async function monitorPulseboardProvider(params: {
  accountId: string;
  config: CoreConfig;
  runtime: unknown;
  abortSignal: AbortSignal;
  statusSink: ReturnType<typeof createAccountStatusSink>;
}): Promise<void> {
  // Stub: A real implementation would open a WebSocket or long-poll connection to
  // the PulseBoard server and route incoming messages to the runtime.
  // This stub simply waits until aborted.
  await new Promise<void>((resolve) => {
    const onAbort = () => resolve();
    params.abortSignal.addEventListener("abort", onAbort, { once: true });
  });
}
```

**Gotchas:**
- `composeAccountWarningCollectors` with zero collectors passed is fine — it returns a no-op. Verify the IRC import also has `composeWarningCollectors` (an additional export) — PulseBoard does not need it, only `composeAccountWarningCollectors`.
- `createComputedAccountStatusAdapter` is generic: `<TAccount, TProbe>`. The `snapshot` parameter in `buildChannelSummary` will have `probe` typed as `TProbe | undefined`. Access `snapshot.probe` and `snapshot.lastProbeAt` carefully.
- `DEFAULT_ACCOUNT_ID` used in `createDefaultChannelRuntimeState` needs to come from `openclaw/plugin-sdk/account-id` (where IRC imports it for `runtime-api.ts`) — confirm the import in `channel.ts` matches where it is actually needed.
- The `groups` section from IRC (which handles per-channel `requireMention` and `toolPolicy`) is omitted for PulseBoard since the platform does not have per-board config in the requirements. If needed later, it follows the same pattern.
- `getChatChannelMeta("pulseboard")` will return metadata for the `pulseboard` channel ID. This requires the channel to be registered in the core channel registry. For bundled plugins, this registration happens automatically via the plugin manifest. The `meta` object returned may be minimal or empty for an unknown channel ID — this is acceptable behavior.

