  createPluginRuntimeStore<PluginRuntime>("PulseBoard runtime not initialized");

export { getPulseboardRuntime, setPulseboardRuntime };
export function clearPulseboardRuntime() { /* call setRuntime with undefined */ }
```

---

### 8. `extensions/pulseboard/src/accounts.ts`

Account resolution. Primary local imports: `./types.js`.

Key SDK imports:
```typescript
import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import { resolveMergedAccountConfig } from "openclaw/plugin-sdk/account-resolution";
import { tryReadSecretFileSync } from "openclaw/plugin-sdk/core";
import { normalizeResolvedSecretInputString } from "openclaw/plugin-sdk/secret-input";
```

Exports:
- **`ResolvedPulseboardAccount`** type: `{ accountId, enabled, name?, configured, apiKey, apiKeySource: "env"|"apiKeyFile"|"config"|"none", serverUrl, username, config: PulseboardAccountConfig }`
- `listPulseboardAccountIds(cfg)` and `resolveDefaultPulseboardAccountId(cfg)` — from `createAccountListHelpers("pulseboard", { normalizeAccountId })`
- **`resolvePulseboardAccount({ cfg, accountId? })`** — merges config, resolves API key from env (`PULSEBOARD_API_KEY`) / file / config, marks `configured` true when `apiKey && serverUrl && username` are all non-empty
- `listEnabledPulseboardAccounts(cfg)` — filter to enabled accounts

API key resolution priority (mirroring IRC password resolution):
1. `process.env.PULSEBOARD_API_KEY` (default account only)
2. `apiKeyFile` path → `tryReadSecretFileSync`
3. `normalizeResolvedSecretInputString({ value: merged.apiKey })`

---

### 9. `extensions/pulseboard/src/probe.ts`

Stub health check — no real network call since PulseBoard is fictional.

```typescript
import type { CoreConfig } from "./types.js";
import { resolvePulseboardAccount } from "./accounts.js";
import type { PulseboardProbe } from "./types.js";

export async function probePulseboard(
  cfg: CoreConfig,
  opts: { accountId?: string; timeoutMs?: number },
): Promise<PulseboardProbe> {
  const account = resolvePulseboardAccount({ cfg, accountId: opts.accountId });
  // Stub: return metadata without real network I/O
  return {
    serverUrl: account.serverUrl,
    username: account.username,
    latencyMs: undefined,
  };
}
```

---

### 10. `extensions/pulseboard/src/send.ts`

Stub outbound message sender — uses the runtime store pattern.

```typescript
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export async function sendMessagePulseboard(
  to: string,
  text: string,
  opts?: { cfg?: CoreConfig; accountId?: string; replyTo?: string },
): Promise<{ messageId?: string }> {
  // In a real implementation, getPulseboardRuntime() would return a live
  // PulseBoard client connection. Here we validate the runtime is set
  // and return a stub result.
  getPulseboardRuntime(); // throws if not initialized
  return { messageId: undefined };
}
```

---

### 11. `extensions/pulseboard/src/setup-core.ts`

Core (non-UI) setup logic. Pattern mirrors `extensions/irc/src/setup-core.ts`.

Key SDK imports:
```typescript
import type { ChannelSetupAdapter, ChannelSetupInput } from "openclaw/plugin-sdk/channel-setup";
import type { DmPolicy } from "openclaw/plugin-sdk/config-runtime";
import { normalizeAccountId } from "openclaw/plugin-sdk/routing";
import {
  applyAccountNameToChannelSection,
  createSetupInputPresenceValidator,
  createTopLevelChannelAllowFromSetter,
  createTopLevelChannelDmPolicySetter,
  patchScopedAccountConfig,
} from "openclaw/plugin-sdk/setup";
```

Exports:
- **`updatePulseboardAccountConfig(cfg, accountId, patch)`** — calls `patchScopedAccountConfig`
- **`setPulseboardDmPolicy(cfg, dmPolicy)`** — calls `createTopLevelChannelDmPolicySetter({ channel: "pulseboard" })`
- **`setPulseboardAllowFrom(cfg, allowFrom)`** — calls `createTopLevelChannelAllowFromSetter({ channel: "pulseboard" })`
- **`pulseboardSetupAdapter: ChannelSetupAdapter`** — `validateInput` requires `serverUrl`, `apiKey`, `username` when not using env; `applyAccountConfig` patches `serverUrl`, `apiKey`, `apiKeyFile`, `username`, `defaultBoard`

---

### 12. `extensions/pulseboard/src/setup-surface.ts`

Interactive setup wizard. Pattern mirrors `extensions/irc/src/setup-surface.ts`.

Key SDK imports:
```typescript
import {
  createAllowFromSection,
  createPromptParsedAllowFromForAccount,
  createStandardChannelSetupStatus,
  setSetupChannelEnabled,
  formatDocsLink,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard, WizardPrompter } from "openclaw/plugin-sdk/setup";
```

Text inputs for `pulseboardSetupWizard`:
1. **`serverUrl`** — "PulseBoard server URL" (required, validates URL format, normalizes with `.trim()`)
2. **`token`** (maps to `apiKey`) — "PulseBoard API key" (required, sensitive)
3. **`userId`** (maps to `username`) — "PulseBoard username" (required)
4. **`httpHost`** (maps to `defaultBoard`) — "Default board (optional, e.g. #general)" (optional, validates `isBoardTarget`)

Env var detection in `prepare` phase: check `PULSEBOARD_SERVER_URL`, `PULSEBOARD_API_KEY`, `PULSEBOARD_USERNAME` and offer to use env vars if all three are set.

`allowFrom` section: uses `createAllowFromSection` with PulseBoard-specific help text ("Allowlist PulseBoard DMs by sender username.").

`dmPolicy`: `ChannelSetupDmPolicy` pointing to `channels.pulseboard.dmPolicy`.

`completionNote`: "Next: restart gateway and verify status. Command: openclaw channels status --probe".

---

### 13. `extensions/pulseboard/src/channel.ts`

Main plugin definition — the most complex file. Pattern mirrors `extensions/irc/src/channel.ts`.

Key imports (all from SDK or local):
```typescript
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import { formatNormalizedAllowFromEntries } from "openclaw/plugin-sdk/allow-from";
import {
  adaptScopedAccountAccessor,
  createScopedChannelConfigAdapter,
  createScopedDmSecurityResolver,
} from "openclaw/plugin-sdk/channel-config-helpers";
import {
  composeAccountWarningCollectors,
  createAllowlistProviderOpenWarningCollector,
} from "openclaw/plugin-sdk/channel-policy";
import {
  createChannelDirectoryAdapter,
  createResolvedDirectoryEntriesLister,
} from "openclaw/plugin-sdk/directory-runtime";
import { runStoppablePassiveMonitor } from "openclaw/plugin-sdk/extension-shared";
import {
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
} from "openclaw/plugin-sdk/status-helpers";
// local
import { resolvePulseboardAccount, listPulseboardAccountIds, resolveDefaultPulseboardAccountId, type ResolvedPulseboardAccount } from "./accounts.js";
import { PulseboardChannelConfigSchema } from "./config-schema.js";
import { normalizePulseboardTarget, looksLikePulseboardTargetId, isBoardTarget, normalizePulseboardAllowEntry } from "./normalize.js";
import { probePulseboard } from "./probe.js";
import {
  buildBaseChannelStatusSummary,
  createAccountStatusSink,
  chunkTextForOutbound,
  getChatChannelMeta,
  PAIRING_APPROVED_MESSAGE,
  type ChannelPlugin,
} from "./runtime-api.js";
import { getPulseboardRuntime } from "./runtime.js";
import { sendMessagePulseboard } from "./send.js";
import { pulseboardSetupAdapter, pulseboardSetupWizard } from "./setup-surface.js";
import type { CoreConfig, PulseboardProbe } from "./types.js";
```

Plugin shape (`createChatChannelPlugin` call):

```typescript
export const pulseboardPlugin: ChannelPlugin<ResolvedPulseboardAccount, PulseboardProbe> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: { ...getChatChannelMeta("pulseboard"), quickstartAllowFrom: true },
      setup: pulseboardSetupAdapter,
      setupWizard: pulseboardSetupWizard,
      capabilities: {
        chatTypes: ["direct", "group"],
        blockStreaming: true,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: PulseboardChannelConfigSchema,
      config: {
        ...pulseboardConfigAdapter,
        isConfigured: (account) => account.configured,
        describeAccount: (account) => describeAccountSnapshot({ account, configured: account.configured, extra: { serverUrl: account.serverUrl, username: account.username, apiKeySource: account.apiKeySource } }),
      },
      messaging: {
        normalizeTarget: normalizePulseboardTarget,
        targetResolver: {
          looksLikeId: looksLikePulseboardTargetId,
          hint: "<#board|username>",
        },
      },
      resolver: { resolveTargets: async ({ inputs, kind }) => { /* resolve board vs user targets */ } },
      directory: createChannelDirectoryAdapter({
        listPeers: async (params) => listPulseboardDirectoryPeersFromConfig(params),
        listGroups: async (params) => listPulseboardDirectoryBoardsFromConfig(params),
      }),
      status: createComputedAccountStatusAdapter<ResolvedPulseboardAccount, PulseboardProbe>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ account, snapshot }) => ({
          ...buildBaseChannelStatusSummary(snapshot),
          serverUrl: account.serverUrl,
          username: account.username,
        }),
        probeAccount: async ({ cfg, account, timeoutMs }) =>
          probePulseboard(cfg as CoreConfig, { accountId: account.accountId, timeoutMs }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: { serverUrl: account.serverUrl, username: account.username },
        }),
      }),
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          const statusSink = createAccountStatusSink({ accountId: ctx.accountId, setStatus: ctx.setStatus });
          if (!account.configured) {
            throw new Error(`PulseBoard is not configured for account "${account.accountId}".`);
          }
          ctx.log?.info(`[${account.accountId}] starting PulseBoard provider (${account.serverUrl})`);
          await runStoppablePassiveMonitor({
            abortSignal: ctx.abortSignal,
            start: async () => {
              // Stub monitor loop — a real implementation would connect to
              // the PulseBoard WebSocket/SSE feed and dispatch inbound messages.
              await new Promise<void>((resolve) => {
                ctx.abortSignal.addEventListener("abort", () => resolve(), { once: true });
              });
            },
          });
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseboardUser",
        message: PAIRING_APPROVED_MESSAGE,
        normalizeAllowEntry: (entry) => normalizePulseboardAllowEntry(entry),
        notify: async ({ id, message }) => {
          await sendMessagePulseboard(id, message);
        },
      },
    },
    security: {
      resolveDmPolicy: pulseboardDmPolicyResolver,
      collectWarnings: pulseboardSecurityWarnings,
    },
    outbound: {
      base: {
        deliveryMode: "direct",
        chunker: chunkTextForOutbound,
        chunkerMode: "markdown",
        textChunkLimit: 4000,
      },
      attachedResults: {
        channel: "pulseboard",
        sendText: async ({ cfg, to, text, accountId, replyToId }) =>
          sendMessagePulseboard(to, text, { cfg: cfg as CoreConfig, accountId: accountId ?? undefined, replyTo: replyToId ?? undefined }),
        sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
          sendMessagePulseboard(to, mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text, { cfg: cfg as CoreConfig, accountId: accountId ?? undefined }),
      },
    },
  });
```

Also define in this file:
- **`pulseboardConfigAdapter`** via `createScopedChannelConfigAdapter`
- **`pulseboardDmPolicyResolver`** via `createScopedDmSecurityResolver`
- **`pulseboardSecurityWarnings`** via `composeAccountWarningCollectors` (warn when dmPolicy="open" without allowlist)
- Directory listers via `createResolvedDirectoryEntriesLister` (one for peers, one for boards)

---

### 14. `extensions/pulseboard/index.ts`

Entry point — exact mirror of `extensions/irc/index.ts`:

```typescript
