// Target normalization for PulseBoard.
//
// PulseBoard uses two target forms:
//   - Boards: "#board-name"  (group chats, prefix required)
//   - DMs:    "username"     (direct messages, no prefix)
//
// Both board names and usernames consist of lowercase letters, digits, and
// hyphens only. Leading/trailing whitespace is always trimmed.

const BOARD_PATTERN = /^#[a-z0-9][a-z0-9-]*$/;
const USERNAME_PATTERN = /^[a-z0-9][a-z0-9-]*$/;

/**
 * Returns true if the raw string looks like a PulseBoard board name.
 * A board name starts with "#" followed by at least one alphanumeric character.
 */
export function isBoardTarget(raw: string): boolean {
  return raw.startsWith("#");
}

/**
 * Normalizes a PulseBoard target (board or username).
 * Returns the normalized string, or null if invalid.
 */
export function normalizePulseboardTarget(raw: string): string | null {
  const trimmed = raw.trim().toLowerCase();
  if (!trimmed) {
    return null;
  }
  if (trimmed.startsWith("#")) {
    // Board target: "#board-name"
    const slug = trimmed.replace(/^#+/, "#");
    if (BOARD_PATTERN.test(slug)) {
      return slug;
    }
    return null;
  }
  // DM target: plain username
  if (USERNAME_PATTERN.test(trimmed)) {
    return trimmed;
  }
  return null;
}

/**
 * Returns true if the raw string looks like a valid PulseBoard target id
 * (board or username), without fully normalizing.
 */
export function looksLikePulseboardTargetId(raw: string): boolean {
  const trimmed = raw.trim().toLowerCase();
  if (!trimmed) {
    return false;
  }
  if (trimmed.startsWith("#")) {
    return BOARD_PATTERN.test(trimmed.replace(/^#+/, "#"));
  }
  return USERNAME_PATTERN.test(trimmed);
}

/**
 * Normalizes a PulseBoard allowFrom entry (a username).
 * Wildcards ("*") are preserved. Returns null for invalid input.
 */
export function normalizePulseboardAllowEntry(raw: string): string | null {
  const trimmed = raw.trim().toLowerCase();
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  if (USERNAME_PATTERN.test(trimmed)) {
    return trimmed;
  }
  return null;
}

