import { describe, expect, it } from "vitest";
import {
  listPulseboardAccountIds,
  resolvePulseboardAccount,
  type ResolvedPulseboardAccount,
} from "./accounts.js";
import { pulseboardPlugin } from "./channel.js";
import { isBoardTarget, normalizePulseboardTarget } from "./normalize.js";
import type { CoreConfig } from "./types.js";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeConfig(overrides?: object): CoreConfig {
  return { channels: { pulseboard: { ...overrides } } } as CoreConfig;
}

function makeFullConfig(
  opts: { serverUrl: string; apiKey: string; username: string } = {
    serverUrl: "https://board.example.com",
    apiKey: "pb_live_test123",
    username: "testbot",
  },
): CoreConfig {
  return makeConfig(opts);
}

// ---------------------------------------------------------------------------
// resolvePulseboardAccount
// ---------------------------------------------------------------------------

describe("resolvePulseboardAccount", () => {
  it("returns configured=false for an empty config", () => {
    const cfg = makeConfig();
    const account = resolvePulseboardAccount({ cfg });
    expect(account.configured).toBe(false);
    expect(account.enabled).toBe(true);
    expect(account.apiKey).toBe("");
    expect(account.serverUrl).toBe("");
    expect(account.username).toBe("");
    expect(account.apiKeySource).toBe("none");
  });

  it("returns configured=true when all three required fields are set", () => {
    const cfg = makeFullConfig();
    const account: ResolvedPulseboardAccount = resolvePulseboardAccount({ cfg });
    expect(account.configured).toBe(true);
    expect(account.serverUrl).toBe("https://board.example.com");
    expect(account.username).toBe("testbot");
    expect(account.apiKey).toBe("pb_live_test123");
    expect(account.apiKeySource).toBe("config");
  });

  it("returns configured=false when apiKey is missing", () => {
    const cfg = makeConfig({ serverUrl: "https://board.example.com", username: "testbot" });
    const account = resolvePulseboardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("returns configured=false when serverUrl is missing", () => {
    const cfg = makeConfig({ apiKey: "pb_live_test123", username: "testbot" });
    const account = resolvePulseboardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("returns enabled=false when explicitly disabled", () => {
    const cfg = makeConfig({
      enabled: false,
      serverUrl: "https://board.example.com",
      apiKey: "pb_live_test123",
      username: "testbot",
    });
    const account = resolvePulseboardAccount({ cfg });
    expect(account.enabled).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// listPulseboardAccountIds
// ---------------------------------------------------------------------------

describe("listPulseboardAccountIds", () => {
  it("returns [DEFAULT_ACCOUNT_ID] for an empty config", () => {
    const ids = listPulseboardAccountIds(makeConfig());
    expect(ids).toHaveLength(1);
    expect(ids[0]).toBe("default");
  });

  it("includes named accounts from the accounts record", () => {
    const cfg = makeConfig({
      accounts: {
        work: { serverUrl: "https://work.example.com", apiKey: "k1", username: "workbot" },
        personal: { serverUrl: "https://personal.example.com", apiKey: "k2", username: "bot2" },
      },
    });
    const ids = listPulseboardAccountIds(cfg);
    expect(ids).toContain("work");
    expect(ids).toContain("personal");
  });
});

// ---------------------------------------------------------------------------
// normalizePulseboardTarget
// ---------------------------------------------------------------------------

describe("normalizePulseboardTarget", () => {
  it("normalizes a valid board target", () => {
    expect(normalizePulseboardTarget("#general")).toBe("#general");
    expect(normalizePulseboardTarget("#ops-team")).toBe("#ops-team");
    expect(normalizePulseboardTarget("  #general  ")).toBe("#general");
  });

  it("normalizes a valid username", () => {
    expect(normalizePulseboardTarget("alice")).toBe("alice");
    expect(normalizePulseboardTarget("BOB")).toBe("bob");
    expect(normalizePulseboardTarget("  carol  ")).toBe("carol");
  });

  it("returns null for empty or invalid input", () => {
    expect(normalizePulseboardTarget("")).toBeNull();
    expect(normalizePulseboardTarget("   ")).toBeNull();
    expect(normalizePulseboardTarget("#")).toBeNull(); // board with no name
    expect(normalizePulseboardTarget("#bad name")).toBeNull(); // space not allowed
    expect(normalizePulseboardTarget("bad name")).toBeNull(); // space not allowed
  });
});

// ---------------------------------------------------------------------------
// isBoardTarget
// ---------------------------------------------------------------------------

describe("isBoardTarget", () => {
  it("identifies board targets", () => {
    expect(isBoardTarget("#general")).toBe(true);
    expect(isBoardTarget("#ops")).toBe(true);
  });

  it("rejects non-board targets", () => {
    expect(isBoardTarget("alice")).toBe(false);
    expect(isBoardTarget("")).toBe(false);
    expect(isBoardTarget("general")).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// pulseboardPlugin structure
// ---------------------------------------------------------------------------

describe("pulseboardPlugin", () => {
  it("has the correct channel id", () => {
    expect(pulseboardPlugin.meta.id).toBe("pulseboard");
  });

  it("supports both direct and group chat types", () => {
    expect(pulseboardPlugin.capabilities.chatTypes).toContain("direct");
    expect(pulseboardPlugin.capabilities.chatTypes).toContain("group");
  });

  it("has blockStreaming enabled", () => {
    expect(pulseboardPlugin.capabilities.blockStreaming).toBe(true);
  });

  it("uses a 4000-character text chunk limit", () => {
    const limit = pulseboardPlugin.outbound?.textChunkLimit;
    expect(limit).toBe(4000);
  });
});

